arguments.file_text:
@inject IJSRuntime JS
@implements IAsyncDisposable

<div class="message-area">
    <div class="message-area-header">
        <h2># @Channel.Name</h2>
        <p>@Channel.Description</p>
    </div>

    <div class="message-list" @ref="messageListRef">
        @if (HasMoreMessages)
        {
            <div class="load-more-sentinel" @ref="sentinelRef"></div>
            @if (IsLoadingMore)
            {
                <div class="loading-indicator">Loading older messages…</div>
            }
        }

        @foreach (var message in Messages)
        {
            <MessageItem Message="message"
                         ThreadReplyCount="GetReplyCount(message.Id)"
                         OnOpenThread="OnOpenThread"
                         OnReact="OnReact" />
        }
    </div>

    <MessageInput Placeholder="@($"Message #{Channel.Name}")"
                  OnSend="OnSendMessage" />
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ReplyCounts { get; set; } = [];
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public bool HasMoreMessages { get; set; } = true;
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private ElementReference messageListRef;
    private ElementReference sentinelRef;
    private IJSObjectReference? jsModule;
    private DotNetObjectReference<MessageArea>? dotNetRef;

    private int GetReplyCount(int messageId) =>
        ReplyCounts.GetValueOrDefault(messageId);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            dotNetRef = DotNetObjectReference.Create(this);
            jsModule = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/Chat/MessageArea.razor.js");
            await jsModule.InvokeVoidAsync("observeSentinel", sentinelRef, dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (!IsLoadingMore && HasMoreMessages)
        {
            await OnLoadMore.InvokeAsync();
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (jsModule is not null)
        {
            try
            {
                await jsModule.InvokeVoidAsync("dispose");
                await jsModule.DisposeAsync();
            }
            catch (JSDisconnectedException) { }
        }
        dotNetRef?.Dispose();
    }
}

let observer = null;

export function observeSentinel(sentinelElement, dotNetRef) {
    dispose();

    if (!sentinelElement) return;

    observer = new IntersectionObserver(
        (entries) => {
            for (const entry of entries) {
                if (entry.isIntersecting) {
                    dotNetRef.invokeMethodAsync("OnSentinelVisible");
                }
            }
        },
        { threshold: 0.1 }
    );
    observer.observe(sentinelElement);
}

export function dispose() {
    if (observer) {
        observer.disconnect();
        observer = null;
    }
}

.message-area {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fff;
    overflow: hidden;
}

.message-area-header {
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.message-area-header h2 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    color: #1a1a1a;
}

.message-area-header p {
    margin: 2px 0 0;
    font-size: 0.8rem;
    color: #777;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.load-more-sentinel {
    height: 1px;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    color: #999;
    font-size: 0.85rem;
}

.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fafafa;
    border-left: 1px solid #e0e0e0;
    overflow: hidden;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.thread-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
}

.close-btn {
    background: none;
    border: none;
    font-size: 1.1rem;
    cursor: pointer;
    color: #777;
    padding: 4px 8px;
    border-radius: 4px;
}

.close-btn:hover {
    background: #eee;
    color: #333;
}

.thread-original {
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
    background: #f0f0f0;
}

.original-author {
    font-weight: 700;
    font-size: 0.9rem;
    margin-bottom: 4px;
}

.original-content {
    font-size: 0.85rem;
    color: #444;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.reply-count {
    padding: 8px 16px;
    font-size: 0.75rem;
    color: #999;
    font-weight: 600;
    text-transform: uppercase;
