}

.reply-time {
    font-size: 0.7rem;
    color: #999;
}

.reply-content {
    font-size: 0.85rem;
    color: #333;
    line-height: 1.4;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-loading {
    text-align: center;
    padding: 24px;
    color: #999;
    font-size: 0.85rem;
}

