<div class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    <div class="thread-original">
        <div class="original-author">@RootMessage.Author</div>
        <div class="original-content">@RootMessage.Content</div>
    </div>

    <div class="thread-replies">
        @if (IsLoading)
        {
            <div class="thread-loading">Loading replies…</div>
        }
        else
        {
            <div class="reply-count">@ThreadMessages.Count @(ThreadMessages.Count == 1 ? "reply" : "replies")</div>
            @foreach (var reply in ThreadMessages)
            {
                <div class="thread-reply">
                    <div class="reply-header">
                        <span class="reply-author">@reply.Author</span>
                        <span class="reply-time">@FormatRelativeTime(reply.SentAt)</span>
                    </div>
                    <div class="reply-content">@reply.Content</div>
                </div>
            }
        }
    </div>

    <MessageInput Placeholder="Reply in thread…"
                  ButtonText="Reply"
                  OnSend="OnReply" />
</div>

@code {
    [Parameter, EditorRequired] public Message RootMessage { get; set; } = default!;
    [Parameter, EditorRequired] public List<Message> ThreadMessages { get; set; } = [];
    [Parameter] public bool IsLoading { get; set; }
    [Parameter] public EventCallback<string> OnReply { get; set; }
    [Parameter] public EventCallback OnClose { get; set; }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        return diff switch
        {
            { TotalMinutes: < 1 } => "just now",
            { TotalMinutes: < 60 } => $"{(int)diff.TotalMinutes} min ago",
            { TotalHours: < 24 } => $"{(int)diff.TotalHours}h ago",
            { TotalDays: < 7 } => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }
}
