.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fafafa;
    border-left: 1px solid #e0e0e0;
    overflow: hidden;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.thread-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
}

.close-btn {
    background: none;
    border: none;
    font-size: 1.1rem;
    cursor: pointer;
    color: #777;
    padding: 4px 8px;
    border-radius: 4px;
}

.close-btn:hover {
    background: #eee;
    color: #333;
}

.thread-original {
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
    background: #f0f0f0;
}

.original-author {
    font-weight: 700;
    font-size: 0.9rem;
    margin-bottom: 4px;
}

.original-content {
    font-size: 0.85rem;
    color: #444;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.reply-count {
    padding: 8px 16px;
    font-size: 0.75rem;
    color: #999;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.03em;
}

.thread-reply {
    padding: 8px 16px;
}

.reply-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.reply-author {
    font-weight: 700;
    font-size: 0.9rem;
}

.reply-time {
    font-size: 0.7rem;
    color: #999;
}

.reply-content {
    font-size: 0.85rem;
    color: #333;
    line-height: 1.4;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-loading {
    text-align: center;
    padding: 24px;
    color: #999;
    font-size: 0.85rem;
}

