arguments.file_text:
@page "/chat"
@rendermode InteractiveServer
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="chat-sidebar">
        <ChannelSidebar Channels="channels"
                        ActiveChannelId="selectedChannelId"
                        OnChannelSelected="SelectChannelAsync" />
    </div>

    <div class="chat-main @(activeThread is null ? "full-width" : "")">
        @if (selectedChannel is not null)
        {
            <MessageArea Channel="selectedChannel"
                         Messages="channelMessages"
                         ReplyCounts="replyCounts"
                         IsLoadingMore="isLoadingMore"
                         HasMoreMessages="hasMoreMessages"
                         OnLoadMore="LoadMoreMessagesAsync"
                         OnSendMessage="SendMessageAsync"
                         OnOpenThread="OpenThreadAsync"
                         OnReact="AddReactionAsync" />
        }
    </div>

    @if (activeThread is not null)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="activeThread"
                         ThreadMessages="threadMessages"
                         IsLoading="isLoadingThread"
                         OnReply="SendThreadReplyAsync"
                         OnClose="CloseThread" />
        </div>
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel> channels = [];
    private int selectedChannelId;
    private Channel? selectedChannel;

    private List<Message> allMessages = [];
    private List<Message> channelMessages = [];
    private Dictionary<int, int> replyCounts = [];
    private bool isLoadingMore;
    private bool hasMoreMessages = true;

    private Message? activeThread;
    private List<Message> threadMessages = [];
    private bool isLoadingThread;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();

        if (channels.Count > 0)
        {
            await SelectChannelAsync(channels[0].Id);
        }
    }

    private async Task SelectChannelAsync(int channelId)
    {
        if (selectedChannelId == channelId && selectedChannel is not null) return;

        selectedChannelId = channelId;
        selectedChannel = channels.FirstOrDefault(c => c.Id == channelId);
        activeThread = null;
        threadMessages = [];
        allMessages = [];
        hasMoreMessages = true;

        allMessages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        hasMoreMessages = allMessages.Count >= PageSize;
        RefreshMessageView();

        _ = ChatService.MarkChannelReadAsync(channelId);
    }

    private async Task LoadMoreMessagesAsync()
    {
        if (isLoadingMore || !hasMoreMessages) return;

        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(selectedChannelId, allMessages.Count, PageSize);
        hasMoreMessages = older.Count >= PageSize;

        allMessages.InsertRange(0, older);
        RefreshMessageView();

        isLoadingMore = false;
    }

    private void RefreshMessageView()
    {
        // Show only top-level messages in the main area
        channelMessages = allMessages.Where(m => m.ReplyToId is null).ToList();

        // Compute reply counts from messages that reference a parent
        replyCounts = allMessages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value)
            .ToDictionary(g => g.Key, g => g.Count());
    }

    private async Task SendMessageAsync(string content)
    {
        var message = await ChatService.SendMessageAsync(selectedChannelId, content, null);
        allMessages.Add(message);
        RefreshMessageView();
    }

    private async Task OpenThreadAsync(int rootMessageId)
    {
        activeThread = allMessages.FirstOrDefault(m => m.Id == rootMessageId);
        if (activeThread is null) return;

        isLoadingThread = true;
        StateHasChanged();

        threadMessages = await ChatService.GetThreadAsync(rootMessageId);

        isLoadingThread = false;
    }

    private void CloseThread()
    {
        activeThread = null;
        threadMessages = [];
    }

    private async Task SendThreadReplyAsync(string content)
    {
        if (activeThread is null) return;

        var reply = await ChatService.SendMessageAsync(selectedChannelId, content, activeThread.Id);

        threadMessages.Add(reply);
        allMessages.Add(reply);
        RefreshMessageView();
    }

    private async Task AddReactionAsync((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistic update: find the message and add/increment the reaction
        var message = allMessages.FirstOrDefault(m => m.Id == args.MessageId)
                      ?? threadMessages.FirstOrDefault(m => m.Id == args.MessageId);

        if (message is not null)
        {
            var existing = message.Reactions.FirstOrDefault(r => r.Emoji == args.Emoji);
            if (existing is not null)
            {
                if (!existing.Users.Contains("You"))
                    existing.Users.Add("You");
            }
            else
            {
                message.Reactions.Add(new Reaction(args.Emoji, ["You"]));
            }
        }
    }
}

.chat-layout {
    display: flex;
    height: calc(100vh - 3.5rem);
    margin: -1rem -1.5rem -1rem -2rem;
    overflow: hidden;
}

.chat-sidebar {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    flex-shrink: 0;
}

.chat-main {
    flex: 1;
    min-width: 0;
    display: flex;
    flex-direction: column;
}

.chat-main.full-width {
    flex: 1;
}

.chat-thread {
    width: 25%;
    min-width: 280px;
    max-width: 400px;
    flex-shrink: 0;
}

